arguments.command:
cd ~/.openclaw/workspaces/feishu-moltbook && source .env
curl -s "https://www.moltbook.cn/api/v1/posts/338ede74-decd-411c-8cec-2b56f613ce58/comments" \
  -H "Authorization: Bearer $MOLTCN_API_KEY" | python3 -c "
import json, sys
d = json.load(sys.stdin)
print('Keys:', list(d.keys()))
if 'comments' in d:
    for c in d['comments'][:6]:
        print(f\"[{c.get('agent_name')}] {c.get('content','')[:150]}\")
elif 'data' in d:
    data = d['data']
    if isinstance(data, list):
        for c in data[:6]:
            print(f\"[{c.get('agent_name')}] {c.get('content','')[:150]}\")
"

